# legal_research_agent.py — simplified excerpt
import anthropic
from pathlib import Path

client = anthropic.Anthropic()

# Load the static contract standards document once at startup.
# This file is 4,500 tokens and never changes during a deployment.
CONTRACT_STANDARDS = Path("docs/contract_standards.md").read_text()

TOOLS = [
    {
        "name": "search_contracts",
        "description": "Full-text search across all contracts in the archive.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string"},
                "contract_type": {
                    "type": "string",
                    "enum": ["nda", "service", "employment", "license"],
                },
            },
            "required": ["query"],
        },
    },
    # ... 11 more tool definitions ...
]


class LegalResearchAgent:
    def __init__(self) -> None:
        # Build the system prompt once and cache it for the process lifetime.
        self._system = [
            {
                "type": "text",
                # Prepend standards doc so it is part of the cached prefix.
                "text": (
                    f"You are a legal research assistant.\n\n"
                    f"## Company Contract Standards\n\n{CONTRACT_STANDARDS}"
                ),
                "cache_control": {"type": "ephemeral"},
            }
        ]

    def query(self, question: str) -> str:
        response = client.messages.create(
            model="claude-sonnet-4-5",
            max_tokens=2048,
            system=self._system,
            tools=TOOLS,
            messages=[{"role": "user", "content": question}],
        )

        u = response.usage
        cached = getattr(u, "cache_read_input_tokens", 0)
        created = getattr(u, "cache_creation_input_tokens", 0)

        if cached > 0:
            savings_pct = round((1 - 0.1) * cached / (cached + u.input_tokens) * 100)
            print(f"[cache HIT] Saved ~{savings_pct}% on input tokens this call")
        elif created > 0:
            print(f"[cache MISS] Wrote {created} tokens to cache (1.25x surcharge)")

        return "".join(
            block.text for block in response.content if hasattr(block, "text")
        )


# Usage
agent = LegalResearchAgent()
print(agent.query("Which of our NDAs have non-compete clauses exceeding 24 months?"))
print(agent.query("Summarise indemnification clauses in our SaaS service agreements."))
